loop:                                             ; preds = %bb1, %bb0, %start
  %nonpoison = phi i32 [ 0, %start ], [ %nonpoison, %bb0 ], [ %arg, %bb1 ]
  %i = call i32 @opaque()
  switch i32 %i, label %exit [
    i32 0, label %bb0
    i32 1, label %bb1
  ]

exit:                                             ; preds = %loop
  ret i32 %nonpoison

bb0:                                              ; preds = %loop
  br label %loop

bb1:                                              ; preds = %loop
  br label %loop
}

declare i32 @opaque()

```
